package com.company.supervision.application;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.baomidou.mybatisplus.core.metadata.IPage;import com.baomidou.mybatisplus.extension.plugins.pagination.Page;import com.company.supervision.application.scheduling.AdvancedScheduleService;import com.company.supervision.domain.model.*;import com.company.supervision.domain.model.enumeration.*;import com.company.supervision.domain.model.messaging.TaskRecipient;import com.company.supervision.domain.service.TaskExecutionEngine;import com.company.supervision.entity.dto.*;import com.company.supervision.infrastructure.repository.*;import com.company.supervision.infrastructure.repository.messaging.TaskRecipientMapper;import com.fasterxml.jackson.databind.ObjectMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service public class TaskAppService{private final TaskMapper tasks;private final TaskNodeMapper nodes;private final ScheduleMapper schedules;private final ExecutionMapper executions;private final TaskExecutionEngine engine;private final AdvancedScheduleService advanced;private final TaskRecipientMapper recipients;private final ObjectMapper json;private final RobotAppService robotAppService;public TaskAppService(TaskMapper t,TaskNodeMapper n,ScheduleMapper s,ExecutionMapper e,TaskExecutionEngine x,SchedulerAppService legacy,AdvancedScheduleService a,TaskRecipientMapper r,ObjectMapper j,RobotAppService robotService){tasks=t;nodes=n;schedules=s;executions=e;engine=x;advanced=a;recipients=r;json=j;robotAppService=robotService;}
 @Transactional public Long createTask(TaskCreateRequest r){AutomationTask t=new AutomationTask();copy(t,r);t.setStatus(TaskStatus.ENABLED.getCode());tasks.insert(t);saveChildren(t.getId(),r);return t.getId();}@Transactional public void updateTask(Long id,TaskCreateRequest r){AutomationTask t=required(id);copy(t,r);tasks.updateById(t);nodes.delete(new LambdaQueryWrapper<TaskNode>().eq(TaskNode::getTaskId,id));recipients.deleteByTask(id);saveChildren(id,r);}@Transactional public void deleteTask(Long id){nodes.delete(new LambdaQueryWrapper<TaskNode>().eq(TaskNode::getTaskId,id));recipients.deleteByTask(id);TaskSchedule s=schedules.selectByTaskId(id);if(s!=null)schedules.deleteById(s.getId());advanced.remove(id);tasks.deleteById(id);}public IPage<AutomationTask>listTasks(String name,int page,int size){LambdaQueryWrapper<AutomationTask>w=new LambdaQueryWrapper<>();if(name!=null&&!name.isBlank())w.like(AutomationTask::getName,name);return tasks.selectPage(new Page<>(Math.max(page,1),Math.max(size,1)),w.orderByDesc(AutomationTask::getId));}public TaskDetail getTask(Long id){TaskDetail d=new TaskDetail();d.setTask(required(id));d.setNodes(nodes.selectByTaskIdOrdered(id));d.setSchedule(schedules.selectByTaskId(id));d.setRecipients(recipients.byTask(id));return d;}public Long executeNow(Long id){required(id);return engine.execute(id);}
 private void copy(AutomationTask t,TaskCreateRequest r){t.setName(r.getName());t.setDescription(r.getDescription());t.setScheduleType(r.getSchedule()!=null&&!"MANUAL".equals(r.getSchedule().getMode())?1:(r.getScheduleType()==null?0:r.getScheduleType()));t.setCreatedBy(r.getCreatedBy());validateMessageTarget(r.getMessageDefinition());try{t.setMessageDefinition(r.getMessageDefinition()==null?null:json.writeValueAsString(r.getMessageDefinition()));}catch(Exception e){throw new IllegalArgumentException(e);}} private void validateMessageTarget(Map<String,Object> message){if(message==null||!"GROUP_WEBHOOK".equals(String.valueOf(message.get("channel"))))return;LinkedHashSet<Long>ids=new LinkedHashSet<>();Object many=message.get("webhookIds");if(many instanceof Collection<?>)for(Object value:(Collection<?>)many){Long id=longValue(value);if(id!=null)ids.add(id);}Long legacy=longValue(message.get("webhookId"));if(legacy!=null)ids.add(legacy);robotAppService.validateSelectable(ids);message.put("webhookIds",new ArrayList<>(ids));message.remove("webhookId");} private Long longValue(Object value){if(value==null)return null;if(value instanceof Number)return((Number)value).longValue();try{return Long.valueOf(value.toString());}catch(NumberFormatException ignored){return null;}}
 private void saveChildren(Long id,TaskCreateRequest r){if(r.getNodes()!=null)for(TaskCreateRequest.NodeInput x:r.getNodes()){TaskNode n=new TaskNode();n.setTaskId(id);n.setNodeType(x.getNodeType());n.setNodeOrder(x.getNodeOrder());n.setConfig(x.getConfig());nodes.insert(n);}if(r.getRecipients()!=null)for(TaskCreateRequest.RecipientInput x:r.getRecipients()){TaskRecipient q=new TaskRecipient();q.setTaskId(id);q.setRecipientType(x.getRecipientType());q.setRecipientRef(x.getRecipientRef());q.setMentionMode(x.getMentionMode());recipients.insert(q);}advanced.save(id,r.getSchedule(),r.getCronExpression());}
 private AutomationTask required(Long id){AutomationTask t=tasks.selectById(id);if(t==null)throw new IllegalArgumentException("Task not found: "+id);return t;}}